Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
sinks/drain.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

module.exports = function drain (op, done) {
  var read, abort

  // Declared here so that it captures the drain's stack trace
  var doneLackingErr
  if (!done) {
    doneLackingErr = new Error('no done callback supplied')
  }

  function sink (_read) {
    read = _read
    if(abort) return sink.abort()
    //this function is much simpler to write if you
    //just use recursion, but by using a while loop
    //we do not blow the stack if the stream happens to be sync.
    ;(function next() {
        var loop = true, cbed = false
        while(loop) {
          cbed = false
          read(null, function (end, data) {
            cbed = true
            if(end = end || abort) {
              loop = false
              if(done) done(end === true ? null : end)
                 <PLACEHOLDER>

                console.warn(doneLackingErr)
                throw end
              }
            }
            else if(op && false === op(data) || abort) {
              loop = false
              read(abort || true, done || function () {})
            }
            else if(!loop){
              next()
            }
          })
          if(!cbed) {
            loop = false
            return
          }
        }
      })()
  }

  sink.abort = function (err, cb) {
    if('function' == typeof err)
      cb = err, err = true
    abort = err || true
    if(read) return read(abort, cb || function () {})
  }

  return sink
}

In the original code, <PLACEHOLDER> has the value:

-                 else if(end && end !== true) {
In the mutated code, <PLACEHOLDER> has the value:

+                 else if(end && end === true) {


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-8f6b188/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the change is:
- Original: `else if(end && end !== true)` - triggers when `end` is a real error (not just `true`)
- Mutated: `else if(end && end === true)` - triggers when `end` is exactly `true` (stream ended normally)

In the original code, when a stream ends with a real error (not `true`), and there's no `done` callback, it logs a warning and throws the error. With the mutation, this behavior is inverted - it would throw when the stream ends normally (`true`) instead of when there's a real error.

I need to write a test that:
1. Creates a stream that ends with a real error
2. Has no `done` callback
3. Expects the error to be thrown (original behavior)
4. With the mutation, no throw would happen for real errors (but would throw for normal end)

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink error handling without done callback", () => {
  it("should throw when stream ends with a real error and no done callback is provided", () => {
    // Create a source that immediately ends with a real error
    const realError = new Error("stream error");

    let callCount = 0;
    const source = (_abort: any, cb: (end: any, data?: any) => void) => {
      callCount++;
      if (callCount === 1) {
        // First call: return some data
        cb(null, "data1");
      } else {
        // Second call: end with a real error
        cb(realError);
      }
    };

    // No done callback - this should cause the error to be thrown
    // In original: end !== true means real error triggers throw
    // In mutated: end === true means only normal end triggers throw (real error won't throw)
    const sink = drain(null); // no done callback

    expect(() => {
      sink(source);
    }).toThrow(realError);
  });
});
```

Wait, I need to think about this more carefully. The `drain` function uses a while loop and callbacks, so the throw might happen asynchronously or synchronously depending on the source.

Let me reconsider - the source I create should be synchronous (cbed = true before loop ends), so the throw should propagate synchronously.

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink error handling without done callback", () => {
  it("should throw when stream ends with a real error and no done callback is provided", () => {
    const realError = new Error("stream error");

    // Synchronous source that ends immediately with a real error
    const source = (_abort: any, cb: (end: any, data?: any) => void) => {
      cb(realError);
    };

    // No done callback provided
    const sink = drain(null);

    // Original: else if(end && end !== true) -> throws for real errors
    // Mutated: else if(end && end === true) -> does NOT throw for real errors
    expect(() => {
      sink(source);
    }).toThrow(realError);
  });
});
